import { Link } from "react-router-dom";
import "../styles/mainmenu/MainMenu.css";
import React, { useRef } from 'react';

const Start = () => {
  const fileInputRef = useRef(null);

  const cargarPartidaDesdeArchivo = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const partida = JSON.parse(e.target.result);
        const { equipo, calendario, numLigas } = partida;

        localStorage.setItem('equipo', JSON.stringify(equipo));
        localStorage.setItem('calendario', JSON.stringify(calendario));
        localStorage.setItem('numLigas', JSON.stringify(numLigas));

        alert('Partida cargada con éxito.');
        window.location.reload(); // Recarga la app si es necesario
      } catch (err) {
        alert('El archivo no es válido.');
      }
    };
    reader.readAsText(file);
  };

  return (
    <>
      <button
        className="menu-button"
        onClick={() => fileInputRef.current.click()}
      >
        Load Game
      </button>
      <input
        type="file"
        accept=".json"
        style={{ display: 'none' }}
        ref={fileInputRef}
        onChange={cargarPartidaDesdeArchivo}
      />
    </>
  );
};


export default StartPage; // Asegúrate de exportar por defecto
